// Merge PowerCare data: enrich existing entries or add new ones
const powerCareMap = new Map(powerCareCustomers.map(pc => [pc.clientId, pc]));

const mergedCustomerData = _baseCustomerData.map(c => {
  const pc = powerCareMap.get(c.clientId ?? '');
  if (!pc) return c;
  // Mark as seen so we don't add it again below
  powerCareMap.delete(c.clientId ?? '');
  return {
    ...c,
    isPowerCare: true,
    powerCareCaseNumber: pc.powerCareCaseNumber || undefined,
    powerCareTrackingNumber: pc.powerCareTrackingNumber || undefined,
    // Enrich contact info if missing in SolarEdge import
    email: c.email || pc.email,
    phone: c.phone || pc.phone,
    address: c.address || pc.address,
    city: c.city || pc.city,
    state: c.state || pc.state,
    zip: c.zip || pc.zip,
    name: c.name || pc.name,
    notes: [c.notes, pc.notes].filter(Boolean).join(' | '),
  };
});

// Add PowerCare customers not found in SolarEdge list
for (const pc of powerCareMap.values()) {
  mergedCustomerData.push({
    clientId: pc.clientId,
    name: pc.name,
    email: pc.email,
    phone: pc.phone,
    address: pc.address,
    city: pc.city,
    state: pc.state,
    zip: pc.zip,
    type: 'residential',
    clientStatus: 'O&M',
    solarEdgeSiteId: '',
    systemType: 'SolarEdge',
    notes: pc.notes,
    installDate: '',
    peakPower: 0,
    isPowerCare: true,
    powerCareCaseNumber: pc.powerCareCaseNumber || undefined,
    powerCareTrackingNumber: pc.powerCareTrackingNumber || undefined,
  });
}

export { mergedCustomerData };
